import sys

class Solution:
    def sortArray(self, nums: list[int]) -> list[int]:
        if len(nums) <= 1: return nums;

        mid = len(nums) // 2;
        left = self.sortArray(nums[:mid]);
        right = self.sortArray(nums[mid:]);

        result = [];
        while left and right:
            if left[-1] < right[-1]:
                result.append(left.pop());
            else:
                result.append(right.pop());
        result.extend(left);
        result.extend(right);
        return result

