#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    vector<int> sortArray(vector<int>& nums) {
        if (nums.size() <= 1) return nums;

        int mid = nums.size() / 2;
        vector<int> left = sortArray(vector<int>(nums.begin(), nums.begin() + mid));
        vector<int> right = sortArray(vector<int>(nums.begin() + mid, nums.end()));

        vector<int> result;
        while (left.size() > 0 && right.size() > 0) {
            if (left.back() < right.back()) {
                result.push_back(left.back());
                left.pop_back();
            } else {
                result.push_back(right.back());
                right.pop_back();
            }
        }

        result.insert(result.end(), left.begin(), left.end());
        result.insert(result.end(), right.begin(), right.end());
        return result;
    }
};

int main() {
    Solution solution;
    vector<int> nums;
    int a;
    while (cin >> a) nums.push_back(a);
    vector<int> sols = solution.sortArray(nums);
    for (int i = 0; i < sols.size(); i++) cout << sols[i] << ' ';
    return 0;
}
